#include <bits/stdc++.h>
using namespace std;
int n,b,a[1000005],sum;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>b;
	a[1]=1;
	for(int i=2; i<=n; i++) {
		if(!a[i])
			for(int j=i; j<=n; j+=i) {
				a[j]=i;
			}
	}
	for(int i=1; i<=n; i++) {
		if(a[i]<=b)
			sum++;
	}
	cout<<sum;
	return 0;
}
